function calculateMA(dayCount, _data) {
    const result = [];
    for (let i = 0, len = _data.length; i < len; i++) {
        if (i < dayCount) {
            result.push('-');
            continue;
        }
        let sum = 0;
        for (let j = 0; j < dayCount; j++) {
            sum += _data[i - j][1];
        }
        result.push(sum / dayCount);
    }
    return result;
}

