for (let j = 0; j < suburstData.length; ++j) {
    const level1 = suburstData[j].children;
    for (let i = 0; i < level1.length; ++i) {
        const block = level1[i].children;
        const bookScore = [];
        let bookScoreId;
        for (let star = 0; star < block.length; ++star) {
            const style = (function (name) {
                switch (name) {
                    case '5☆':
                        bookScoreId = 0;
                        return suburstStyle.star5;
                    case '4☆':
                        bookScoreId = 1;
                        return suburstStyle.star4;
                    case '3☆':
                        bookScoreId = 2;
                        return suburstStyle.star3;
                    case '2☆':
                        bookScoreId = 3;
                        return suburstStyle.star2;
                }
            })(block[star].name);

            if (block[star].children) {
                block[star].children.forEach(book => {

                    book['value'] = 1;
                    book['label'] = {
                        color: style.color
                    };

                    let value = 1;
                    if (bookScoreId === 0 || bookScoreId === 3) {
                        value = 5;
                    }

                    if (bookScore[bookScoreId]) {
                        bookScore[bookScoreId].value += value;
                    } else {
                        bookScore[bookScoreId] = {
                            color: suburstColors[bookScoreId],
                            value: value
                        };
                    }
                });
            }
        }
    }
}

